#include<iostream>#include<algorithm>#include<cmath>#include<string>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        string s;        cin>>s;        int open_bracket_not_closed=0;        int close_bracket_not_opened=0;        for(int i=0;i<n;i++){            if(s[i]=='(') open_bracket_not_closed++;            else{                if(open_bracket_not_closed>0) open_bracket_not_closed--;                else close_bracket_not_opened++;            }        }        cout<<min(open_bracket_not_closed,close_bracket_not_opened)<<"\n";    }}